function getProperty&lt;T, K extends keyof T&gt;(obj: T, key: K): T[K] {
  return obj[key];
}

const personne = { nom: "Alice", age: 30, ville: "Douala" };

console.log(getProperty(personne, "nom"));  // "Alice"
