Ainsi, TypeScript lève une erreur à la compilation si la clé n'existe pas dans l'objet.

```typescript
// Version simple : paramètre par défaut uniquement
function creerTableau&lt;T = string&gt;(elements: T[]): T[] {
  return [...elements];
}

// Version avec contrainte supplémentaire (T ne peut pas être never)
function creerTableauAvecContrainte&lt;T = string&gt;(elements: T[]): T[] {
  return [...elements];
}

// Appel sans spécifier le type : T = string
const tableauChaines = creerTableau(["a", "b", "c"]);
// type : string[]

// Appel avec le type number
const tableauNombres = creerTableau&lt;number&gt;([1, 2, 3]);
// type : number[]

// Appel avec un type personnalisé
interface Personne { nom: string; }
const tableauPersonnes = creerTableau&lt;Personne&gt;([{ nom: "Alice" }, { nom: "Bob" }]);
```
Le paramètre par défaut permet d'utiliser la fonction sans avoir à préciser le type quand on utilise des chaînes, tout en conservant la flexibilité pour d'autres types.

```typescript
// Définition de l'interface Produit
export interface Produit&lt;T extends string | number&gt; {
  id: T;
  nom: string;
  prix: number;
  quantite: number;
}

// Classe Stock avec contrainte sur T
export class Stock&lt;T extends string | number&gt; {
  private produits: Produit&lt;T&gt;[] = [];

  ajouter(produit: Produit&lt;T&gt;): void {
    // Vérifier si un produit avec le même id existe déjà
    const existe = this.produits.some(p => p.id === produit.id);
    if (existe) {
      console.log(`Produit avec l'id ${produit.id} existe déjà. Mise à jour de la quantité.`);
      this.produits = this.produits.map(p =>
        p.id === produit.id
          ? { ...p, quantite: p.quantite + produit.quantite }
          : p
      );
    } else {
      this.produits.push(produit);
      console.log(`Produit "${produit.nom}" ajouté avec succès.`);
    }
  }

  trouverParId(id: T): Produit&lt;T&gt; | undefined {
    return this.produits.find(p => p.id === id);
  }

  valeurTotale(): number {
    return this.produits.reduce((total, produit) => total + (produit.prix * produit.quantite), 0);
  }

  afficherStock(): void {
    console.log("\n=== ÉTAT DU STOCK ===");
    if (this.produits.length === 0) {
      console.log("Stock vide");
      return;
    }
    this.produits.forEach(p => {
      console.log(`ID: ${p.id} | ${p.nom} | ${p.prix} FCFA | Qté: ${p.quantite} | Total: ${p.prix * p.quantite} FCFA`);
    });
    console.log(`Valeur totale du stock : ${this.valeurTotale()} FCFA`);
  }
}

// TESTS
console.log("=== STOCK AVEC ID STRING (CODE BARRE) ===");
const stockString = new Stock&lt;string&gt;();
stockString.ajouter({ id: "BARRE-001", nom: "Savon", prix: 500, quantite: 50 });
stockString.ajouter({ id: "BARRE-002", nom: "Riz 5kg", prix: 3500, quantite: 20 });
stockString.ajouter({ id: "BARRE-001", nom: "Savon", prix: 500, quantite: 30 }); // Mise à jour
stockString.afficherStock();

console.log("\n=== STOCK AVEC ID NUMBER (RÉFÉRENCE) ===");
const stockNumber = new Stock&lt;number&gt;();
stockNumber.ajouter({ id: 101, nom: "Tomates", prix: 300, quantite: 100 });
stockNumber.ajouter({ id: 102, nom: "Oignons", prix: 400, quantite: 75 });
stockNumber.afficherStock();

// Recherche d'un produit
const produitTrouve = stockNumber.trouverParId(101);
console.log(`\nRecherche du produit 101 :`, produitTrouve);

// Erreur à la compilation si on essaie d'utiliser un type non autorisé
// const stockErreur = new Stock&lt;boolean&gt;(); // ❌ Type 'boolean' ne satisfait pas la contrainte
```
